  function checkSettingsExpiry(settings) {
    try {
      if (!settings || !settings.updated_at) {
        console.debug('STOQ - Invalid settings data structure');
        return null;
      }

      if (!settings.cache) {
        console.debug('STOQ - settings caching disabled');
        return null;
